#include<bits/stdc++.h>
using namespace std;
int main()
{
//	freopen("cute.in","r",stdin);
//	freopen("cute.out","w",stdout);
	long long n,k;
	cin >> n >> k;
	while(n--)
	{
		string s;
		cin >> s;
		long long a = 1;
		int flag = 1, flag1 = 1;
		for(int i = 0; i < s.size(); i++){
			long long x = s[i] - '0';
			if(x == 0){
				cout << "kawaii" << endl;
				flag1 = 0;
				break;
			}
			a *= x;
			if(a > k){
				a %= k;
				flag = 0;
			}
		}
		if(flag1 == 0)continue;
		else if(flag == 0)cout << "dame\n";
		else cout << "kawaii\n";
	}
 }
